"""
iOS shim for psutil._psutil_osx.

The original psutil ships `_psutil_osx.abi3.so`, a C extension that
calls Apple's IOKit (IOPSCopyPowerSourcesInfo, IOServiceGetMatchingService,
…). Those are private APIs on iOS and trip ITMS-90338 at App Store
upload, so the build script `wrap-loose-dylibs.sh` deletes the .so.

After deletion `from . import _psutil_osx` would raise ImportError →
`import psutil` fails → every shell command that touches stats
(`top`, `nproc`, the `top` builtin, etc.) prints "psutil not available".

This Python shim provides the same surface the .so did, implemented
via Apple's PUBLIC Mach + sysctl APIs so it's App-Store-clean. Numbers
that iOS doesn't expose (per-process introspection beyond getpid(),
disk SMART counters, sensors) are returned as safe zeros / empty —
psutil's higher-level wrappers gracefully degrade rather than fault.

Implementation strategy:

  Memory  → Mach host_statistics64(HOST_VM_INFO64) + sysctl hw.memsize
  CPU     → Mach host_statistics(HOST_CPU_LOAD_INFO) +
            host_processor_info(PROCESSOR_CPU_LOAD_INFO) for per-core
  Counts  → sysctl hw.logicalcpu / hw.physicalcpu
  Boot    → sysctl kern.boottime
  Pids    → just os.getpid() (iOS sandbox blocks proc enumeration)
  Process → minimal kinfo lookup for self only; others raise

All ctypes calls are guarded so a syscall failure surfaces as zero-
values, never a Python exception that would unwind into psutil.
"""
from __future__ import annotations

import ctypes
import ctypes.util
import os
import sys
import time
from ctypes import (
    POINTER, Structure, byref, c_char, c_char_p, c_int, c_int32, c_int64,
    c_size_t, c_uint, c_uint32, c_uint64, c_ulong, c_void_p, sizeof,
)

# ── TCP connection-state codes (from <netinet/tcp_var.h>) ────────────
# psutil uses these as keys in a TCP_STATUSES dict; values must match
# what kernel headers define so any future C extension swap is binary-
# compatible.
TCPS_CLOSED       = 0
TCPS_LISTEN       = 1
TCPS_SYN_SENT     = 2
TCPS_SYN_RECEIVED = 3
TCPS_ESTABLISHED  = 4
TCPS_CLOSE_WAIT   = 5
TCPS_FIN_WAIT_1   = 6
TCPS_CLOSING      = 7
TCPS_LAST_ACK     = 8
TCPS_FIN_WAIT_2   = 9
TCPS_TIME_WAIT    = 10
PSUTIL_CONN_NONE  = 128  # psutil-internal sentinel

# ── Process states (from <sys/proc.h>) ───────────────────────────────
SIDL   = 1   # process being created
SRUN   = 2   # currently runnable
SSLEEP = 3   # sleeping on an address
SSTOP  = 4   # process debugging or suspension
SZOMB  = 5   # awaiting collection by parent

# ── Version sanity check — psutil/__init__.py asserts that
#    int(psutil.__version__.replace('.', '')) == cext.version
#    on import, raising ImportError("version conflict: ...") if they
#    differ. The bundled psutil ships at 5.9.8 → version must be 598.
#    Update both numbers together if the bundle ever moves to a newer
#    psutil. ──────────────────────────────────────────────────────────
version = 598

# ── Page size constant psutil expects at module top ──────────────────
try:
    PAGESIZE = os.sysconf("SC_PAGESIZE")
except (ValueError, OSError):
    PAGESIZE = 16384  # iOS arm64 default

# Cached at module-import (≈ Python interp start) so kinfo_oneshot
# returns a stable creation time across calls — without this every
# psutil.Process(self).create_time() would change, breaking caches
# downstream.
_PROCESS_START_TIME = time.time()


# ── libSystem handle (host_statistics, sysctl, host port) ────────────
def _load_libsystem():
    """Locate libSystem (the Apple C runtime). Returns None on failure
    so all callers can fall back to safe defaults. find_library can
    return None if the dynamic loader cache is being rebuilt; the
    explicit path catches that."""
    for cand in (ctypes.util.find_library("System"),
                 "/usr/lib/libSystem.dylib",
                 "/usr/lib/libSystem.B.dylib"):
        if not cand:
            continue
        try:
            return ctypes.CDLL(cand, use_errno=True)
        except OSError:
            continue
    return None


_libc = _load_libsystem()


def _mach_host_self():
    """Return the host port (mach_port_t). 0 on failure."""
    if _libc is None:
        return 0
    try:
        _libc.mach_host_self.restype = c_uint
        return int(_libc.mach_host_self())
    except (AttributeError, OSError):
        return 0


def _mach_task_self():
    """Return the current task's Mach port (mach_port_t = c_uint).

    mach_task_self_ is a GLOBAL C VARIABLE in libsyscall_internal,
    not a function. ctypes.CDLL.<attr> on a variable symbol returns
    a function-pointer object whose `int()` blows up with
        ValueError: invalid literal for int() with base 10: b'…'
    because the int() conversion grabs the raw 8-byte address bytes.

    The right way to read a global variable through ctypes is
    `ctypes.c_uint.in_dll(lib, name).value`, which interprets the
    symbol's storage as the requested type.

    On Darwin we also have `mach_task_self()` as a function-style
    accessor in some SDKs; try that as a second-best fallback before
    giving up.
    """
    if _libc is None:
        return 0
    try:
        return int(c_uint.in_dll(_libc, "mach_task_self_").value)
    except (ValueError, AttributeError, OSError):
        pass
    try:
        _libc.mach_task_self.restype = c_uint
        return int(_libc.mach_task_self())
    except (AttributeError, OSError):
        return 0


# ── sysctl wrapper for byname queries ────────────────────────────────
def _sysctlbyname(name: str, fmt: str = "Q", default=0):
    """Query a sysctl variable by name. fmt is a struct-style code:
    'Q' = unsigned 64, 'I' = unsigned 32, 'i' = signed 32, 's' = string.
    Returns `default` on any failure."""
    if _libc is None:
        return default
    try:
        if fmt == "s":
            buf = ctypes.create_string_buffer(1024)
            sz = c_size_t(1024)
            rc = _libc.sysctlbyname(name.encode(), buf, byref(sz), None, 0)
            if rc != 0:
                return default
            return buf.value.decode("utf-8", "replace").rstrip("\x00")
        if fmt == "Q":
            v = c_uint64(0); sz = c_size_t(8)
        elif fmt == "I":
            v = c_uint32(0); sz = c_size_t(4)
        elif fmt == "i":
            v = c_int32(0);  sz = c_size_t(4)
        else:
            return default
        rc = _libc.sysctlbyname(name.encode(), byref(v), byref(sz), None, 0)
        if rc != 0:
            return default
        return int(v.value)
    except (AttributeError, OSError):
        return default


# ── HOST_VM_INFO64 — memory statistics ───────────────────────────────
class _vm_statistics64(Structure):
    _fields_ = [
        ('free_count',                              c_uint32),
        ('active_count',                            c_uint32),
        ('inactive_count',                          c_uint32),
        ('wire_count',                              c_uint32),
        ('zero_fill_count',                         c_uint64),
        ('reactivations',                           c_uint64),
        ('pageins',                                 c_uint64),
        ('pageouts',                                c_uint64),
        ('faults',                                  c_uint64),
        ('cow_faults',                              c_uint64),
        ('lookups',                                 c_uint64),
        ('hits',                                    c_uint64),
        ('purges',                                  c_uint64),
        ('purgeable_count',                         c_uint32),
        ('speculative_count',                       c_uint32),
        ('decompressions',                          c_uint64),
        ('compressions',                            c_uint64),
        ('swapins',                                 c_uint64),
        ('swapouts',                                c_uint64),
        ('compressor_page_count',                   c_uint32),
        ('throttled_count',                         c_uint32),
        ('external_page_count',                     c_uint32),
        ('internal_page_count',                     c_uint32),
        ('total_uncompressed_pages_in_compressor',  c_uint64),
    ]


_HOST_VM_INFO64 = 4
_HOST_VM_INFO64_COUNT = sizeof(_vm_statistics64) // sizeof(c_int)


def _host_vm_stats():
    """Return a populated _vm_statistics64, or None on failure."""
    if _libc is None:
        return None
    try:
        host = _mach_host_self()
        if host == 0:
            return None
        _libc.host_statistics64.restype = c_int
        stats = _vm_statistics64()
        count = c_uint(_HOST_VM_INFO64_COUNT)
        rc = _libc.host_statistics64(
            host, _HOST_VM_INFO64, byref(stats), byref(count))
        if rc != 0:
            return None
        return stats
    except (AttributeError, OSError):
        return None


def virtual_mem():
    """Return (total, active, inactive, wired, free, speculative) in
    bytes. Matches the .so's tuple order so _psosx.py unpacking works."""
    total = _sysctlbyname("hw.memsize", "Q", 0)
    s = _host_vm_stats()
    if s is None:
        return (total, 0, 0, 0, total, 0)
    return (
        total,
        s.active_count    * PAGESIZE,
        s.inactive_count  * PAGESIZE,
        s.wire_count      * PAGESIZE,
        s.free_count      * PAGESIZE,
        s.speculative_count * PAGESIZE,
    )


def swap_mem():
    """Return (total, used, free, sin, sout) in bytes. iOS has no
    on-disk swap file — everything is the compressor — so report
    compressor_page_count as `used` and total_uncompressed as the
    pre-compression size (≈ total)."""
    s = _host_vm_stats()
    if s is None:
        return (0, 0, 0, 0, 0)
    used = s.compressor_page_count * PAGESIZE
    sin  = s.swapins  * PAGESIZE
    sout = s.swapouts * PAGESIZE
    total_uncompressed = s.total_uncompressed_pages_in_compressor * PAGESIZE
    total = max(used, total_uncompressed)
    free = max(0, total - used)
    return (total, used, free, sin, sout)


# ── HOST_CPU_LOAD_INFO — aggregate CPU times ─────────────────────────
class _host_cpu_load_info(Structure):
    _fields_ = [
        # cpu_state[CPU_STATE_USER, _SYSTEM, _IDLE, _NICE]
        ('cpu_ticks', c_uint * 4),
    ]


_HOST_CPU_LOAD_INFO = 3
_HOST_CPU_LOAD_INFO_COUNT = sizeof(_host_cpu_load_info) // sizeof(c_int)
_CPU_STATE_USER, _CPU_STATE_SYSTEM, _CPU_STATE_IDLE, _CPU_STATE_NICE = 0, 1, 2, 3


def _ticks_to_seconds(ticks):
    # Mach reports ticks at the host's CLK_TCK rate (typically 100 Hz);
    # convert to seconds the same way psutil's C ext does.
    try:
        return float(ticks) / float(os.sysconf("SC_CLK_TCK"))
    except (ValueError, OSError):
        return float(ticks) / 100.0


def cpu_times():
    """Return (user, nice, system, idle) seconds since boot."""
    if _libc is None:
        return (0.0, 0.0, 0.0, 0.0)
    try:
        host = _mach_host_self()
        if host == 0:
            return (0.0, 0.0, 0.0, 0.0)
        _libc.host_statistics.restype = c_int
        info = _host_cpu_load_info()
        count = c_uint(_HOST_CPU_LOAD_INFO_COUNT)
        rc = _libc.host_statistics(host, _HOST_CPU_LOAD_INFO,
                                    byref(info), byref(count))
        if rc != 0:
            return (0.0, 0.0, 0.0, 0.0)
        return (
            _ticks_to_seconds(info.cpu_ticks[_CPU_STATE_USER]),
            _ticks_to_seconds(info.cpu_ticks[_CPU_STATE_NICE]),
            _ticks_to_seconds(info.cpu_ticks[_CPU_STATE_SYSTEM]),
            _ticks_to_seconds(info.cpu_ticks[_CPU_STATE_IDLE]),
        )
    except (AttributeError, OSError):
        return (0.0, 0.0, 0.0, 0.0)


# ── PROCESSOR_CPU_LOAD_INFO — per-core CPU times ─────────────────────
def per_cpu_times():
    """Return a list of (user, nice, system, idle) tuples, one per
    logical CPU. Falls back to a single `cpu_times()` row if the
    Mach call fails."""
    if _libc is None:
        return [cpu_times()]
    try:
        host = _mach_host_self()
        if host == 0:
            return [cpu_times()]
        n_cpus_p = c_uint(0)
        info_p = c_void_p()
        info_count = c_uint(0)
        _libc.host_processor_info.restype = c_int
        # PROCESSOR_CPU_LOAD_INFO == 2
        rc = _libc.host_processor_info(host, 2,
                                        byref(n_cpus_p),
                                        byref(info_p),
                                        byref(info_count))
        if rc != 0 or info_p.value is None:
            return [cpu_times()]
        n = int(n_cpus_p.value)
        # The buffer is `unsigned int [n_cpus * CPU_STATE_MAX]`; CPU_STATE_MAX = 4.
        ArrType = c_uint * int(info_count.value)
        arr = ArrType.from_address(info_p.value)
        out = []
        for i in range(n):
            base = i * 4
            out.append((
                _ticks_to_seconds(arr[base + _CPU_STATE_USER]),
                _ticks_to_seconds(arr[base + _CPU_STATE_NICE]),
                _ticks_to_seconds(arr[base + _CPU_STATE_SYSTEM]),
                _ticks_to_seconds(arr[base + _CPU_STATE_IDLE]),
            ))
        # Free the Mach VM region the kernel allocated for us. Without
        # this, every call to per_cpu_times() leaks a few KB.
        try:
            _libc.vm_deallocate(_mach_task_self(),
                                info_p,
                                info_count.value * sizeof(c_uint))
        except (AttributeError, OSError):
            pass
        return out or [cpu_times()]
    except (AttributeError, OSError, ValueError):
        return [cpu_times()]


def cpu_count_logical():
    return _sysctlbyname("hw.logicalcpu", "I", os.cpu_count() or 1)


def cpu_count_cores():
    return _sysctlbyname("hw.physicalcpu", "I", cpu_count_logical())


def cpu_stats():
    """Return (ctx_switches, interrupts, soft_interrupts, syscalls).
    iOS doesn't expose these counters publicly — return zeros so
    psutil.cpu_stats() doesn't break."""
    return (0, 0, 0, 0)


def cpu_freq():
    """Return (current, min, max) MHz. iOS hides clockspeed behind
    sysctl hw.cpufrequency_max which most builds redact; report the
    bus frequency as `current` if available, else zeros."""
    cur = _sysctlbyname("hw.cpufrequency",     "Q", 0) // 1_000_000
    mn  = _sysctlbyname("hw.cpufrequency_min", "Q", 0) // 1_000_000
    mx  = _sysctlbyname("hw.cpufrequency_max", "Q", 0) // 1_000_000
    return (float(cur), float(mn), float(mx))


# ── boot time (sysctl kern.boottime → struct timeval) ────────────────
class _timeval(Structure):
    _fields_ = [('tv_sec', c_int64), ('tv_usec', c_int64)]


def boot_time():
    if _libc is None:
        return 0.0
    try:
        tv = _timeval()
        sz = c_size_t(sizeof(_timeval))
        rc = _libc.sysctlbyname(b"kern.boottime", byref(tv),
                                byref(sz), None, 0)
        if rc != 0:
            return 0.0
        return float(tv.tv_sec) + float(tv.tv_usec) / 1_000_000.0
    except (AttributeError, OSError):
        return 0.0


# ── Things iOS doesn't expose — return safe defaults ─────────────────
def disk_io_counters():
    return {}


def disk_partitions():
    """Just the writable Documents dir — iOS apps see only their
    sandbox so reporting more would lie."""
    home = os.path.expanduser("~")
    return [(home, home, "apfs", "rw,journaled")]


def check_pid_range(pid):
    """psutil.Process.__init__ calls this to reject obviously-wrong
    pids before doing the expensive kinfo lookup. Mirrors the C
    extension's bounds check: 0 ≤ pid ≤ 2**31-1, must be int.
    Raises OverflowError for out-of-range so psutil's wrapper turns
    it into NoSuchProcess like the .so does."""
    if not isinstance(pid, int):
        raise TypeError("pid must be an integer")
    if pid < 0 or pid > 0x7FFFFFFF:
        raise OverflowError("pid is out of valid range")


def set_debug(value):
    """psutil.set_debug() forwards here. We don't have a debug log
    to toggle but accept the call so it doesn't AttributeError."""
    return None


def sensors_battery():
    """Return (percent, minsleft, power_plugged_int) via UIDevice's
    PUBLIC API — App Store clean. UIDevice exposes:
      batteryLevel   float in [0,1] (-1 if monitoring is off / not
                     a battery-bearing device)
      batteryState   int: 0=unknown, 1=unplugged, 2=charging, 3=full

    iOS doesn't publicly expose seconds-remaining, so minsleft is -1
    (psutil's wrapper turns that into POWER_TIME_UNKNOWN).

    Per-call CFUNCTYPE casts keep `objc.objc_msgSend.restype` thread-
    safe — same pattern offlinai_shell._darwin_gpu_info() uses to
    avoid the PAC race that bit Python 3.14's _ios_support.py.
    """
    if _libc is None:
        raise NotImplementedError("libSystem unavailable")
    try:
        objc = ctypes.CDLL("/usr/lib/libobjc.dylib")
        # objc_getClass / sel_registerName signatures
        objc.objc_getClass.restype = c_void_p
        objc.objc_getClass.argtypes = [c_char_p]
        objc.sel_registerName.restype = c_void_p
        objc.sel_registerName.argtypes = [c_char_p]

        UIDevice = objc.objc_getClass(b"UIDevice")
        if not UIDevice:
            raise NotImplementedError("UIDevice class missing — not iOS?")

        sel_currentDevice = objc.sel_registerName(b"currentDevice")
        sel_setMon        = objc.sel_registerName(b"setBatteryMonitoringEnabled:")
        sel_batteryLevel  = objc.sel_registerName(b"batteryLevel")
        sel_batteryState  = objc.sel_registerName(b"batteryState")

        # [UIDevice currentDevice] — returns id, treat as void*.
        send_id = ctypes.cast(
            objc.objc_msgSend,
            ctypes.CFUNCTYPE(c_void_p, c_void_p, c_void_p))
        device = send_id(UIDevice, sel_currentDevice)
        if not device:
            raise NotImplementedError("[UIDevice currentDevice] returned nil")

        # [device setBatteryMonitoringEnabled:YES] — required before
        # batteryLevel/batteryState return real values. Without this
        # batteryLevel = -1 forever.
        send_void_bool = ctypes.cast(
            objc.objc_msgSend,
            ctypes.CFUNCTYPE(None, c_void_p, c_void_p, ctypes.c_bool))
        send_void_bool(device, sel_setMon, True)

        # [device batteryLevel] — float in [0, 1].
        send_float = ctypes.cast(
            objc.objc_msgSend,
            ctypes.CFUNCTYPE(ctypes.c_float, c_void_p, c_void_p))
        level = send_float(device, sel_batteryLevel)

        # [device batteryState] — NSInteger (long on arm64).
        send_long = ctypes.cast(
            objc.objc_msgSend,
            ctypes.CFUNCTYPE(ctypes.c_long, c_void_p, c_void_p))
        state = int(send_long(device, sel_batteryState))

        if level < 0:
            raise NotImplementedError("battery level not available")
        percent = float(level) * 100.0
        # batteryState: 0=unknown, 1=unplugged, 2=charging, 3=full.
        # psutil wants power_plugged ∈ {0, 1}: 1 if charging or full.
        power_plugged = 1 if state in (2, 3) else 0
        # iOS doesn't expose minutes-left publicly; -1 → POWER_TIME_UNKNOWN.
        return (percent, -1, power_plugged)
    except (AttributeError, OSError) as e:
        raise NotImplementedError(f"battery probe failed: {e}")


def net_io_counters():
    return {}


def users():
    return []


def pids():
    """iOS sandbox restricts proc_listallpids; return just our own
    pid so `psutil.pids()` is non-empty and per-process iteration
    has at least the current process to look at."""
    return [os.getpid()]


# ── Per-process introspection ────────────────────────────────────────
# Most of these are unreachable on iOS for processes other than self;
# raise OSError so psutil's wrappers fall back to AccessDenied.

def _own_pid_only(pid):
    if pid != os.getpid():
        raise OSError(13, "iOS sandbox forbids cross-process introspection")


def proc_kinfo_oneshot(pid):
    """Return the 11-tuple matching kinfo_proc_map in psutil/_psosx.py:
        0  ppid
        1  ruid    (real user id)
        2  euid    (effective user id)
        3  suid    (saved user id)
        4  rgid    (real group id)
        5  egid    (effective group id)
        6  sgid    (saved group id)
        7  ttynr
        8  ctime   (process creation time, unix seconds)
        9  status  (SIDL/SRUN/SSLEEP/SSTOP/SZOMB)
       10  name
    """
    _own_pid_only(pid)
    ppid = os.getppid()
    uid = os.getuid()
    gid = os.getgid()
    name = os.path.basename(sys.executable) or "python"
    return (
        ppid,
        uid, uid, uid,            # ruid, euid, suid
        gid, gid, gid,            # rgid, egid, sgid
        0,                        # ttynr (no controlling tty in iOS sandbox)
        _PROCESS_START_TIME,      # ctime — module-import time used as
                                  #   a stable proxy for our own start
                                  #   time (we don't have proc_pidinfo
                                  #   on iOS to read the real value).
        SRUN,
        name,
    )


class _mach_task_basic_info(Structure):
    """sys/proc_info.h MACH_TASK_BASIC_INFO layout — gives us
    resident_size and virtual_size of the current task."""
    _fields_ = [
        ('virtual_size',    c_uint64),
        ('resident_size',   c_uint64),
        ('resident_size_max', c_uint64),
        ('user_time_secs',   c_uint32),
        ('user_time_usecs',  c_uint32),
        ('system_time_secs', c_uint32),
        ('system_time_usecs', c_uint32),
        ('policy', c_int),
        ('suspend_count', c_int),
    ]


_MACH_TASK_BASIC_INFO = 20
_MACH_TASK_BASIC_INFO_COUNT = sizeof(_mach_task_basic_info) // sizeof(c_int)


def _self_task_info():
    """Run task_info(mach_task_self_, MACH_TASK_BASIC_INFO, …) and
    return the populated struct, or None on failure. Used to surface
    the current process's real RSS / virtual size for `top`'s last
    line — without this the Python row reads 0 B forever."""
    if _libc is None:
        return None
    try:
        task = _mach_task_self()
        if task == 0:
            return None
        _libc.task_info.restype = c_int
        info = _mach_task_basic_info()
        count = c_uint(_MACH_TASK_BASIC_INFO_COUNT)
        rc = _libc.task_info(task, _MACH_TASK_BASIC_INFO,
                             byref(info), byref(count))
        if rc != 0:
            return None
        return info
    except (AttributeError, OSError):
        return None


def proc_pidtaskinfo_oneshot(pid):
    """psutil expects an 8-tuple matching pidtaskinfo_map in
    psutil/_psosx.py:
        0 cpuutime  (cpu_user)
        1 cpustime  (cpu_sys)
        2 rss
        3 vms
        4 pfaults
        5 pageins
        6 numthreads
        7 volctxsw   (voluntary context switches)
    For self we fill rss / vms from Mach task_info(MACH_TASK_BASIC_INFO);
    ctx switches / pfaults / pageins aren't publicly exposed so stay 0.
    """
    _own_pid_only(pid)
    try:
        ru = os.times()
        cpu_user, cpu_system = ru.user, ru.system
    except OSError:
        cpu_user = cpu_system = 0.0
    # Thread count: best-effort via threading.active_count() — covers
    # Python-managed threads, which is what `top` cares about. Native
    # background threads created by C extensions are missed.
    try:
        import threading
        thr_count = threading.active_count()
    except Exception:
        thr_count = 1
    info = _self_task_info()
    if info is None:
        return (cpu_user, cpu_system, 0, 0, 0, 0, thr_count, 0)
    return (
        cpu_user,
        cpu_system,
        int(info.resident_size),  # rss
        int(info.virtual_size),   # vms
        0,                        # pfaults
        0,                        # pageins
        thr_count,                # numthreads
        0,                        # volctxsw
    )


def proc_name(pid):
    _own_pid_only(pid)
    return os.path.basename(sys.executable) or "python"


def proc_exe(pid):
    _own_pid_only(pid)
    return sys.executable or ""


def proc_cmdline(pid):
    _own_pid_only(pid)
    return list(sys.argv)


def proc_environ(pid):
    _own_pid_only(pid)
    return "\x00".join(f"{k}={v}" for k, v in os.environ.items()) + "\x00"


def proc_cwd(pid):
    _own_pid_only(pid)
    try:
        return os.getcwd()
    except OSError:
        return ""


def proc_memory_uss(pid):
    _own_pid_only(pid)
    return 0


def proc_open_files(pid):
    _own_pid_only(pid)
    return []


def proc_connections(pid, families, types):
    _own_pid_only(pid)
    return []


def proc_num_fds(pid):
    _own_pid_only(pid)
    # Best-effort: count open fds in /dev/fd.
    try:
        return len(os.listdir("/dev/fd"))
    except OSError:
        return 0


def proc_threads(pid):
    _own_pid_only(pid)
    # (tid, user_time, system_time)
    try:
        ru = os.times()
        return [(0, ru.user, ru.system)]
    except OSError:
        return [(0, 0.0, 0.0)]


# Backwards-compat alias some psutil paths use.
def proc_pidinfo(pid, *args, **kw):
    return proc_kinfo_oneshot(pid)
